shapes.frame_eqs_str:
redsine=.55+.1*bass*sin(time*3);
greensine=.7+.1*mid*sin(time*2);
bluesine=.7+.1*treb*sin(time);

redif=if(above(bass,1.2),redsine,if(above(redif,.95),0,redif*.95));
greenif=if(above(mid,1.2),greensine,if(above(greenif,.95),0,greenif*.95));
blueif=if(above(treb,1.2),bluesine,if(above(blueif,.95),0,blueif*.95));

border_r=redif;
border_g=greenif;
border_b=blueif;

border_a=1-(.45*(bass+mid));
a=(.0155*(bass+mid));

warp:
shader_body { 
 vec4 tmpvar_1;
 tmpvar_1.w = 1.0;
 tmpvar_1.xyz = (texture (sampler_main, uv).xyz * 0.98);
 ret = tmpvar_1.xyz;
}

comp:
shader_body { 
 vec3 ret_1;
 vec4 tmpvar_2;
 tmpvar_2 = texture (sampler_main, uv);
 float tmpvar_3;
 tmpvar_3 = ((texture (sampler_blur2, uv).xyz * scale2) + bias2).x;
 ret_1 = (tmpvar_2.xyz * 2.4);
 ret_1 = (ret_1 * texture (sampler_main, (tmpvar_3 + (tmpvar_3 * tmpvar_2.xyz).xy)).xyz);
 vec4 tmpvar_4;
 tmpvar_4.w = 1.0;
 tmpvar_4.xyz = ret_1;
 ret = tmpvar_4.xyz;
}
